# OIDC Configuration
OIDC_CONFIG = {
    'issuer': os.environ.get('OIDC_ISSUER', 'https://accounts.google.com'),
    'client_id': os.environ.get('OIDC_CLIENT_ID', 'your-client-id'),
    'client_secret': os.environ.get('OIDC_CLIENT_SECRET', 'your-client-secret'),
    'redirect_uri': os.environ.get('OIDC_REDIRECT_URI', 'http://localhost:5000/callback'),
    'scope': os.environ.get('OIDC_SCOPE', 'openid email profile'),
}

# Cache for OIDC discovery and JWKS
_oidc_discovery_cache = None
_jwks_cache = None


def get_oidc_discovery():
    """Fetch and cache the OIDC discovery document."""
    global _oidc_discovery_cache
    if _oidc_discovery_cache is None:
        discovery_url = f"{OIDC_CONFIG['issuer']}/.well-known/openid-configuration"
        response = requests.get(discovery_url, timeout=10)
        response.raise_for_status()
        _oidc_discovery_cache = response.json()
    return _oidc_discovery_cache


def get_jwks():
    """Fetch and cache the JWKS (JSON Web Key Set) from the provider."""
    global _jwks_cache
    if _jwks_cache is None:
        discovery = get_oidc_discovery()
        jwks_uri = discovery['jwks_uri']
        response = requests.get(jwks_uri, timeout=10)
        response.raise_for_status()
        _jwks_cache = response.json()
    return _jwks_cache


def decode_id_token(id_token):
    """Decode and validate the ID token using the provider's JWKS."""
    jwks = get_jwks()
    
    # Get the unverified header to find the key ID
    unverified_header = jwt.get_unverified_header(id_token)
    
    # Find the matching key
    rsa_key = None
    for key in jwks.get('keys', []):
        if key.get('kid') == unverified_header.get('kid'):
            rsa_key = key
            break
    
    if rsa_key is None:
        # Refresh JWKS cache and try again
        global _jwks_cache
        _jwks_cache = None
        jwks = get_jwks()
        for key in jwks.get('keys', []):
            if key.get('kid') == unverified_header.get('kid'):
                rsa_key = key
                break
    
    if rsa_key is None:
        raise JWTError("Unable to find matching key in JWKS")
    
    # Decode and validate the token
    claims = jwt.decode(
        id_token,
        rsa_key,
        algorithms=['RS256'],
        audience=OIDC_CONFIG['client_id'],
        issuer=OIDC_CONFIG['issuer'],
    )
    
    return claims


def login_required(f):
    """Decorator to require authentication for a route."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            session['next_url'] = request.url
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


