@app.route('/login')
def login():
    """Initiate the OIDC authorization code flow."""
    try:
        discovery = get_oidc_discovery()
    except Exception as e:
        return jsonify({'error': 'Failed to fetch OIDC discovery document', 'details': str(e)}), 500
    
    # Generate a random state parameter to prevent CSRF
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state
    
    # Generate a nonce to prevent replay attacks
    nonce = secrets.token_urlsafe(32)
    session['oauth_nonce'] = nonce
    
    # Build the authorization URL
    authorization_endpoint = discovery['authorization_endpoint']
    params = {
        'client_id': OIDC_CONFIG['client_id'],
        'response_type': 'code',
        'scope': OIDC_CONFIG['scope'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'state': state,
        'nonce': nonce,
    }
    
    auth_url = f"{authorization_endpoint}?{urlencode(params)}"
    return redirect(auth_url)


@app.route('/callback')
def callback():
    """Handle the OIDC callback after user authentication."""
    # Check for errors from the provider
    error = request.args.get('error')
    if error:
        error_description = request.args.get('error_description', 'Unknown error')
        return jsonify({
            'error': error,
            'error_description': error_description
        }), 400
    
    # Validate the state parameter
    state = request.args.get('state')
    stored_state = session.pop('oauth_state', None)
    if state is None or state != stored_state:
        return jsonify({'error': 'Invalid state parameter. Possible CSRF attack.'}), 403
    
    # Get the authorization code
    code = request.args.get('code')
    if code is None:
        return jsonify({'error': 'No authorization code received'}), 400
    
    # Exchange the authorization code for tokens
    try:
        discovery = get_oidc_discovery()
        token_endpoint = discovery['token_endpoint']
        
        token_data = {
            'grant_type': 'authorization_code',
            'code': code,
            'redirect_uri': OIDC_CONFIG['redirect_uri'],
            'client_id': OIDC_CONFIG['client_id'],
            'client_secret': OIDC_CONFIG['client_secret'],
        }
        
        token_response = requests.post(
            token_endpoint,
            data=token_data,
            headers={'Content-Type': 'application/x-www-form-urlencoded'},
            timeout=10,
        )
        token_response.raise_for_status()
        tokens = token_response.json()
        
    except requests.RequestException as e:
        return jsonify({'error': 'Failed to exchange authorization code', 'details': str(e)}), 500
    
    # Extract tokens
    id_token = tokens.get('id_token')
    access_token = tokens.get('access_token')
    refresh_token = tokens.get('refresh_token')
    
    if id_token is None:
        return jsonify({'error': 'No id_token in token response'}), 500
    
    # Decode and validate the ID token
    try:
        claims = decode_id_token(id_token)
    except JWTError as e:
        return jsonify({'error': 'Failed to decode id_token', 'details': str(e)}), 500
    
    # Validate the nonce
    stored_nonce = session.pop('oauth_nonce', None)
    token_nonce = claims.get('nonce')
    if stored_nonce is not None and token_nonce != stored_nonce:
        return jsonify({'error': 'Invalid nonce. Possible replay attack.'}), 403
    
    # Optionally fetch additional user info from the userinfo endpoint
    user_info = {}
    userinfo_endpoint = discovery.get('userinfo_endpoint')
    if userinfo_endpoint and access_token:
        try:
            userinfo_response = requests.get(
                userinfo_endpoint,
                headers={'Authorization': f'Bearer {access_token}'},
                timeout=10,
            )
            if userinfo_response.status_code == 200:
                user_info = userinfo_response.json()
        except requests.RequestException:
            pass  # UserInfo is optional; proceed with id_token claims
    
    # Merge claims and user info (user_info takes precedence for overlapping keys)
    merged_user = {**claims, **user_info}
    
    # Store user information in the session
    session['user'] = {
        'sub': merged_user.get('sub'),
        'email': merged_user.get('email'),
        'email_verified': merged_user.get('email_verified'),
        'name': merged_user.get('name'),
        'given_name': merged_user.get('given_name'),
        'family_name': merged_user.get('family_name'),
        'picture': merged_user.get('picture'),
        'locale': merged_user.get('locale'),
    }
    
    # Store tokens in session (be cautious with sensitive data)
    session['tokens'] = {
        'access_token': access_token,
        'refresh_token': refresh_token,
        'id_token': id_token,
        'token_type': tokens.get('token_type'),
        'expires_in': tokens.get('expires_in'),
    }
    
    # Redirect to the originally requested URL or home
    next_url = session.pop('next_url', url_for('index'))
    return redirect(next_url)


