@app.route('/logout')
def logout():
    """Log out the user and optionally redirect to the provider's logout endpoint."""
    id_token = None
    if 'tokens' in session:
        id_token = session['tokens'].get('id_token')
    
    # Clear the session
    session.clear()
    
    # Try to use the provider's end_session_endpoint for full SSO logout
    try:
        discovery = get_oidc_discovery()
        end_session_endpoint = discovery.get('end_session_endpoint')
        
        if end_session_endpoint:
            params = {
                'post_logout_redirect_uri': url_for('index', _external=True),
            }
            if id_token:
                params['id_token_hint'] = id_token
            
            logout_url = f"{end_session_endpoint}?{urlencode(params)}"
            return redirect(logout_url)
    except Exception:
        pass  # If discovery fails, just do local logout
    
    return redirect(url_for('index'))


